{
  "day": "1",
  "heading": "Reach Gangotri from Dehradun",
  "sub_heading": "Drive distance: 242 km | Drive Duration: 8 hours",
  "details": "Transport will be arranged from ,Asli Pappu Da Dhaba, Dehradun at 5.00 am. The transport cost is ₹1550 (additional 5% GST) per trekker (one-way) (₹3100 for both onward and return journeys). These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek."
}

{
  "day": "2",
  "heading": "Acclimatization day around Gangotri (10,052 ft)",
  "sub_heading": "Take a short trek up one of the trails around Gangotri and then return to base.",
  "details": ""
}

{
  "day": "3",
  "heading": "Trek from Gangotri (10,052 ft) to Bhoj Kharak (13,220 ft)",
  "sub_heading": "Trek distance: 6 km | Trek Duration: 5-6 hours",
  "details": "Moderate-difficult. Steep ascent all the way. The terrain is rocky in many parts."
}

{
  "day": "4",
  "heading": "Bhoj Kharak (13,220 ft) to Kedar Kharak (14,240 ft)",
  "sub_heading": "Trek distance: 2.5 km | Trek Duration: 3 hours",
  "details": "Moderate-difficult. 1 km of steep ascent followed by 3 km of moderate ascents and descents."
}

{
  "day": "5",
  "heading": "Kedar Kharak (14,240 ft) to Kedartal (16,000 ft) and back to Kedar Kharak (14,240 ft)",
  "sub_heading": "Trek distance: 5.40 km | Trek Duration: 8 hours",
  "details": "Difficult. Continuously ascending trail over a rocky terrain."
}

{
  "day": "6",
  "heading": "Kedar Kharak (14,240 ft) to Gangotri (10,052 ft)",
  "sub_heading": "Trek distance: 8.50 km | Trek Duration: 8 hours",
  "details": "Moderate. Continuously descending trail over a rocky terrain"
}

{
  "day": "7",
  "heading": "Gangotri to Dehradun",
  "sub_heading": "Drive distance: 242 km | Drive Duration: 8 hours",
  "details": "The transport cost is ₹1550 (additional 5% GST) per trekker (one-way) (₹3100 for both onward and return journeys). These are non-AC vehicles. Please pre-book your transport through the dashboard before your trek.\nPlease note: The distance between campsites may vary by 100 meters depending on the weather conditions and the route you take. The altitude may also vary by 100 feet for similar reasons.\nDrop Location and Time: Asli Pappu Da Dhaba, Dehradun at 8.00 pm"
}
